def gen(rng, size):
    m = rng.randint(1, max(1, min(size, 100)))
    n = rng.randint(1, max(1, min(size, 100)))
    base = sorted((rng.randint(-100, 100) for _ in range(m * n)), reverse=True)
    grid = [base[r * n:(r + 1) * n] for r in range(m)]
    for r in range(m):
        grid[r].sort(reverse=True)
    for c in range(n):
        col = sorted((grid[r][c] for r in range(m)), reverse=True)
        for r in range(m):
            grid[r][c] = col[r]
    return [grid]

